--
-- Table structure for table `orders`
--

DROP TABLE IF EXISTS `orders`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `orders` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `order_number` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `user_id` bigint unsigned NOT NULL,
  `driver_id` bigint unsigned DEFAULT NULL,
  `package_id` bigint unsigned NOT NULL,
  `time_slot_id` bigint unsigned NOT NULL,
  `pickup_date` date DEFAULT NULL,
  `delivery_type` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'door_to_door',
  `pickup_address` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `customer_note` text COLLATE utf8mb4_unicode_ci,
  `pickup_latitude` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `pickup_longitude` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `distance` decimal(8,2) DEFAULT NULL,
  `pickup_map_link` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `use_customer_detergent` tinyint(1) NOT NULL DEFAULT '0',
  `use_customer_softener` tinyint(1) NOT NULL DEFAULT '0',
  `wash_temp` enum('เย็น','อุ่น','ร้อน') COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `dry_temp` enum('อุ่น','ปานกลาง','ร้อน') COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `status` enum('pending','picking_up','picked_up','processing','delivering','completed','cancelled') COLLATE utf8mb4_unicode_ci DEFAULT 'pending',
  `payment_status` enum('unpaid','pending_cash','reviewing','paid') COLLATE utf8mb4_unicode_ci DEFAULT 'unpaid',
  `payment_method` enum('transfer','cash') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'transfer',
  `subtotal` decimal(8,2) NOT NULL DEFAULT '0.00',
  `addon_total` decimal(8,2) NOT NULL DEFAULT '0.00',
  `delivery_fee` decimal(10,2) NOT NULL DEFAULT '0.00',
  `selected_addons` json DEFAULT NULL,
  `payment_slip` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `total_price` decimal(8,2) NOT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `orders_order_number_unique` (`order_number`),
  KEY `orders_user_id_foreign` (`user_id`),
  KEY `orders_package_id_foreign` (`package_id`),
  KEY `orders_time_slot_id_foreign` (`time_slot_id`),
  CONSTRAINT `orders_package_id_foreign` FOREIGN KEY (`package_id`) REFERENCES `packages` (`id`),
  CONSTRAINT `orders_time_slot_id_foreign` FOREIGN KEY (`time_slot_id`) REFERENCES `time_slots` (`id`),
  CONSTRAINT `orders_user_id_foreign` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=16 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

